// [#protodoc-title: Custom Header Injection Filter]
//
// The configuration for injecting custom headers into requests and responses.
//
// Custom Header Injection :ref:`configuration overview <config_http_filters_custom_header_injection>`.
// [#extension: envoy.filters.http.custom_header_injection]

message Config {
  option (udpa.annotations.versioning).previous_message_type =
      "envoy.config.filter.http.custom_header_injection.v2.Config";

  // A header injection rule.
  message HeaderInjection {
    // The header name to inject.
    string header_name = 1 [(validate.rules).string = {
      well_known_regex: HTTP_HEADER_NAME
      strict: false
    }];

    // The header value to inject.
    string header_value = 2;
  }

  // List of headers to inject into requests.
  repeated HeaderInjection request_headers = 1;

  // List of headers to inject into responses.
  repeated HeaderInjection response_headers = 2;
}

