using ProtoHeaderInjection =
    envoy::extensions::filters::http::custom_header_injection::v3::Config::HeaderInjection;

/**
 * Encapsulates the filter configuration with STL containers and provides an area for any custom
 * configuration logic.
 */
class Config : public ::Envoy::Router::RouteSpecificFilterConfig,
               public Logger::Loggable<Logger::Id::config> {
public:
  Config(const envoy::extensions::filters::http::custom_header_injection::v3::Config config,
         bool per_route = false);

  const std::vector<ProtoHeaderInjection>& requestHeaders() const { return request_headers_; }
  const std::vector<ProtoHeaderInjection>& responseHeaders() const { return response_headers_; }
  bool doResponse() const { return response_set_; }
  bool doRequest() const { return request_set_; }

private:
  std::vector<ProtoHeaderInjection> request_headers_;
  std::vector<ProtoHeaderInjection> response_headers_;
  bool response_set_;
  bool request_set_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom Header Injection filter injects configurable headers into requests
 * and/or responses.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;

private:
  const ConfigSharedPtr config_;
  mutable const Config* effective_config_{nullptr};
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};

  /**
   * Injects headers into the header map based on the provided injection rules.
   * @param headers the header map to inject headers into.
   * @param injections the list of header injections to apply.
   */
  void injectHeaders(Http::HeaderMap& headers,
                     const std::vector<ProtoHeaderInjection>& injections);

  /**
   * Gets the effective configuration (global or per-route).
   * @return the effective configuration.
   */
  const Config* getConfig() const;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/common/http/utility.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

Config::Config(const envoy::extensions::filters::http::custom_header_injection::v3::Config config,
               const bool per_route) {
  request_headers_.insert(request_headers_.end(), config.request_headers().begin(),
                          config.request_headers().end());
  response_headers_.insert(response_headers_.end(), config.response_headers().begin(),
                           config.response_headers().end());

  request_set_ = !request_headers_.empty();
  response_set_ = !response_headers_.empty();

  // Note: empty configs are fine for the global config, which would be the case for enabling
  //       the filter globally without rules and then applying them at the virtual host or
  //       route level. At the virtual or route level, it makes no sense to have an empty
  //       config so we throw an error.
  if (per_route && !response_set_ && !request_set_) {
    throw EnvoyException("custom_header_injection_filter: Per filter configs must at least "
                         "specify either request or response headers");
  }
}

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    : config_(config) {}

CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(
    Http::RequestHeaderMap& headers, bool) {
  const auto* config = getConfig();
  if (config->doRequest()) {
    injectHeaders(headers, config->requestHeaders());
  }

  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    Http::StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(
    Http::ResponseHeaderMap& headers, bool) {
  const auto* config = getConfig();
  if (config->doResponse()) {
    injectHeaders(headers, config->responseHeaders());
  }
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    Http::StreamEncoderFilterCallbacks& callbacks) {
  encoder_callbacks_ = &callbacks;
}

void CustomHeaderInjectionFilter::injectHeaders(Http::HeaderMap& headers,
                                                const std::vector<ProtoHeaderInjection>& injections) {
  for (const auto& injection : injections) {
    const Http::LowerCaseString header_name(injection.header_name());
    headers.setCopy(header_name, injection.header_value());
  }
}

const Config* CustomHeaderInjectionFilter::getConfig() const {
  // Cached config pointer.
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ = config_.get();
  return effective_config_;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

