using testing::NiceMock;
using testing::Return;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  const std::string request_config_yaml = R"EOF(
request_headers:
  - header_name: x-injected
    header_value: injected-value
)EOF";

  const std::string response_config_yaml = R"EOF(
response_headers:
  - header_name: x-response-injected
    header_value: response-injected-value
)EOF";

  const std::string both_config_yaml = R"EOF(
request_headers:
  - header_name: x-request-injected
    header_value: request-injected-value
response_headers:
  - header_name: x-response-injected
    header_value: response-injected-value
)EOF";

  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::Config config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  NiceMock<Envoy::StreamInfo::MockStreamInfo> req_info_;
};

/**
 * Test basic request header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicRequestTest) {
  initializeFilter(request_config_yaml);
  Http::TestRequestHeaderMapImpl incoming_headers{{"content-type", "application/json"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(incoming_headers, false));
  EXPECT_EQ("injected-value", incoming_headers.get_("x-injected"));
}

/**
 * Test basic response header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicResponseTest) {
  initializeFilter(response_config_yaml);
  Http::TestResponseHeaderMapImpl incoming_headers{{":status", "200"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(incoming_headers, false));
  EXPECT_EQ("response-injected-value", incoming_headers.get_("x-response-injected"));
}

/**
 * Test both request and response header injection.
 */
TEST_F(CustomHeaderInjectionTest, BothRequestAndResponseTest) {
  initializeFilter(both_config_yaml);

  // Test request
  Http::TestRequestHeaderMapImpl request_headers{{"content-type", "application/json"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("request-injected-value", request_headers.get_("x-request-injected"));

  // Test response
  Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("response-injected-value", response_headers.get_("x-response-injected"));
}

/**
 * Test multiple headers injection.
 */
TEST_F(CustomHeaderInjectionTest, MultipleHeadersTest) {
  const std::string multi_request_yaml = R"EOF(
request_headers:
  - header_name: x-header-1
    header_value: value-1
  - header_name: x-header-2
    header_value: value-2
  - header_name: x-header-3
    header_value: value-3
)EOF";

  initializeFilter(multi_request_yaml);
  Http::TestRequestHeaderMapImpl incoming_headers{{"content-type", "application/json"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(incoming_headers, false));
  EXPECT_EQ("value-1", incoming_headers.get_("x-header-1"));
  EXPECT_EQ("value-2", incoming_headers.get_("x-header-2"));
  EXPECT_EQ("value-3", incoming_headers.get_("x-header-3"));
}

/**
 * Test overwriting existing headers.
 */
TEST_F(CustomHeaderInjectionTest, OverwriteExistingHeaderTest) {
  initializeFilter(request_config_yaml);
  Http::TestRequestHeaderMapImpl incoming_headers{{"x-injected", "original-value"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(incoming_headers, false));
  EXPECT_EQ("injected-value", incoming_headers.get_("x-injected"));
}

/**
 * Test empty config throws exception for per-route config.
 */
TEST_F(CustomHeaderInjectionTest, EmptyPerRouteConfigThrows) {
  envoy::extensions::filters::http::custom_header_injection::v3::Config config;
  EXPECT_THROW(Config(config, true), EnvoyException);
}

/**
 * Test empty global config does not throw.
 */
TEST_F(CustomHeaderInjectionTest, EmptyGlobalConfigOk) {
  envoy::extensions::filters::http::custom_header_injection::v3::Config config;
  EXPECT_NO_THROW(Config(config, false));
}

/**
 * Test filter lifecycle methods.
 */
TEST_F(CustomHeaderInjectionTest, FilterLifecycleTest) {
  initializeFilter(both_config_yaml);
  Http::TestRequestHeaderMapImpl request_headers{{"content-type", "application/json"}};
  Buffer::OwnedImpl data("test data");
  Http::TestRequestTrailerMapImpl trailers;

  // Test decode methods
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(trailers));

  // Test encode methods
  Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->encodeData(data, false));

  Http::TestResponseTrailerMapImpl response_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->encodeTrailers(response_trailers));

  Http::MetadataMap metadata_map;
  EXPECT_EQ(Http::FilterMetadataStatus::Continue, filter_->encodeMetadata(metadata_map));

  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

